# Prometheus — availability SLI over rolling 30 minutes
# good_requests = 2xx responses from integration service
# total_requests = all non-4xx requests (exclude client errors)

sum(rate(http_requests_total{
    service="claude-integration",
    status_code=~"2.."
}[30m]))
/
sum(rate(http_requests_total{
    service="claude-integration",
    status_code!~"4.."
}[30m]))
